		if scopes[i].Root != wantRoots[i] || scopes[i].Level != wantLevels[i] {
			t.Errorf("scope[%d] = {%q, %v}, want {%q, %v}", i, scopes[i].Root, scopes[i].Level, wantRoots[i], wantLevels[i])
		}
	}
}

